const input = $input.first().json;
let params = input.params || input;
if (input.query && typeof input.query === 'string') {
  try {
    const parsedQuery = JSON.parse(input.query);
    if (parsedQuery && typeof parsedQuery === 'object') {
      params = { ...params, ...parsedQuery };
    }
  } catch (e) {}
}
let intent = input.intent || params.intent || 'LÊN_LỊCH_BÀI';
if (params.approval_id || params.approvalId) {
  intent = 'DUYỆT_BÀI';
}

let staticData = {};
try {
  const fs = require('fs');
  const path = require('path');
  const filePath = path.join($env.N8N_USER_FOLDER || './.n8n', 'pending_posts.json');
  if (fs.existsSync(filePath)) {
    staticData = JSON.parse(fs.readFileSync(filePath, 'utf8'));
  }
} catch (e) {
  staticData = $getWorkflowStaticData('global');
}
staticData.pendingPosts = staticData.pendingPosts || {};

function saveStaticData(data) {
  try {
    const fs = require('fs');
    const path = require('path');
    const filePath = path.join($env.N8N_USER_FOLDER || './.n8n', 'pending_posts.json');
    fs.mkdirSync(path.dirname(filePath), { recursive: true });
    fs.writeFileSync(filePath, JSON.stringify(data, null, 2), 'utf8');
  } catch (e) {
    // fallback
  }
}

function normalizePlatform(value) {
  const platform = String(value || 'both').toLowerCase();
  if (platform.includes('facebook') && platform.includes('tiktok')) return 'both';
  if (platform.includes('face')) return 'facebook';
  if (platform.includes('tik')) return 'tiktok';
  return platform === 'both' ? 'both' : 'both';
}

function normalizePublishAt(value) {
  if (!value) return new Date().toISOString();
  const lower = String(value).trim().toLowerCase();
  if (['ngay bây giờ', 'ngay bay gio', 'now', 'ngay', 'bây giờ', 'bay gio', 'luôn', 'luon'].includes(lower)) {
    return new Date().toISOString();
  }
  const parsed = Date.parse(value);
  if (Number.isFinite(parsed)) {
    return new Date(parsed).toISOString();
  }
  return value;
}

if (intent === 'DUYỆT_BÀI') {
  let approvalId = params.approval_id || (params.raw_text || '').match(/[A-Z0-9]{8,}/i)?.[0];
  if (approvalId) {
    approvalId = approvalId.toUpperCase();
  }
  let pending = approvalId ? staticData.pendingPosts[approvalId] : null;
  let resolvedApprovalId = approvalId;

  if (!pending) {
    const chatTarget = String(params.chat_id || '');
    let newestPost = null;
    let newestId = null;
    let newestTime = 0;

    for (const [id, post] of Object.entries(staticData.pendingPosts)) {
      if (String(post.chat_id || '') === chatTarget) {
        const createdAt = Date.parse(post.created_at || 0);
        if (Number.isFinite(createdAt) && createdAt > newestTime) {
          newestTime = createdAt;
          newestPost = post;
          newestId = id;
        }
      }
    }

    if (newestPost) {
      pending = newestPost;
      resolvedApprovalId = newestId;
    }
  }

  if (!pending) {
    return [{ json: { action: 'error', chat_id: params.chat_id, message: `Không tìm thấy bài chờ duyệt nào ${approvalId ? `với mã ${approvalId}` : 'gần đây'} cho chat này.` } }];
  }

  delete staticData.pendingPosts[resolvedApprovalId];
  saveStaticData(staticData);
  const normalizedPending = { ...pending, publish_at: normalizePublishAt(pending.publish_at) };
  return [{ json: { ...normalizedPending, action: 'publish', approval_id: resolvedApprovalId, approved_at: new Date().toISOString() } }];
}

const approvalId = `SOC${Date.now().toString(36).toUpperCase()}`;
const post = {
  action: 'approval_request',
  approval_id: approvalId,
  chat_id: params.chat_id || params.admin_chat_id || $env.ADMIN_TELEGRAM_CHAT_ID,
  platform: normalizePlatform(params.platform),
  title: params.title || '',
  content: params.content || params.caption || params.raw_text || '',
  caption: params.caption || params.content || params.raw_text || '',
  image_url: params.image_url || '',
  video_url: params.video_url || '',
  photo_file_id: params.photo_file_id || '',
  video_file_id: params.video_file_id || '',
  publish_at: normalizePublishAt(params.publish_at),
  created_at: new Date().toISOString()
};

staticData.pendingPosts[approvalId] = { ...post, action: 'publish' };
saveStaticData(staticData);
return [{ json: post }];

